# Deobfuscated Code

After resolving all the string lookups, base64 decoding, and control flow flattening, here is the clean version:

```javascript
// Constants
var TAU = 6.283;              // a0_0x72fc0b - Full circle in radians (2π)
var GOLDEN_RATIO = 1.618;     // a0_0x40042a - φ (golden ratio)
var SQRT_HALF = 0.707;        // a0_0xc9463b - √(1/2) ≈ sin(45°)

// Simulation parameters
var simParams = {              // a0_0x5e495a
    attraction: 4000,          // Coulomb-like repulsion constant
    springCoeff: 0.004,        // Default spring stiffness coefficient
    amplification: 0.92,       // Velocity damping factor (misleading name - see verification)
    gravityStrength: 0.0003,   // Centering gravity strength
    streamLimit: 40,           // Max number of particles
    streamDecay: 0.04,         // Particle drag/decay rate
    theta: 0.06               // Camera smoothing interpolation factor
};

// Nodes
var hub = {
    id: 'hub', label: 'Hub',
    r: 26, x: 400, y: 300, vx: 0, vy: 0
};
var alpha = {
    id: 'alpha', label: 'Alpha',
    r: 16, x: 500, y: 200, vx: 0, vy: 0
};
var beta = {
    id: 'beta', label: 'Beta',
    r: 16, x: 300, y: 400, vx: 0, vy: 0
};
var gamma = {
    id: 'gamma', label: 'Gamma',
    r: 14, x: 250, y: 180, vx: 0, vy: 0
};
var delta = {
    id: 'delta', label: 'Delta',
    r: 14, x: 550, y: 380, vx: 0, vy: 0
};
var epsilon = {
    id: 'epsilon', label: 'Epsilon',
    r: 12, x: 350, y: 150, vx: 0, vy: 0
};

var nodes = [hub, alpha, beta, gamma, delta, epsilon]; // a0_0x5e8695

// Springs (edges)
var springs = [                // a0_0x29c167
    { a: 'hub', b: 'alpha',   rest: 160, k: 0.006 },
    { a: 'hub', b: 'beta',    rest: 160, k: 0.005 },
    { a: 'hub', b: 'gamma',   rest: 170, k: 0.004 },
    { a: 'hub', b: 'delta',   rest: 170, k: 0.004 },
    { a: 'hub', b: 'epsilon', rest: 180, k: 0.003 },
    { a: 'alpha', b: 'beta',  rest: 200, k: 0.002 },
    { a: 'gamma', b: 'delta', rest: 220, k: 0.002 },
    { a: 'alpha', b: 'epsilon', rest: 200, k: 0.002 }
];

// Camera state
var camera = { x: 400, y: 300, zoom: 1 };        // a0_0x5c885a
var cameraTarget = { x: 400, y: 300, zoom: 1 };  // a0_0x2b275f

// Particles and frame counter
var particles = [];  // a0_0x4b8ef5
var frameCount = 0;  // a0_0x464d76

// Find a node by ID
function findNodeById(id) {    // a0_0x5ca6ed
    for (var i = 0; i < nodes.length; i++) {
        if (nodes[i].id === id) return nodes[i];
    }
    return null;
}

// Physics step: apply forces and integrate
function applyPhysics() {      // a0_0x3f26b9
    // Coulomb repulsion between all node pairs
    for (var i = 0; i < nodes.length; i++) {
        for (var j = i + 1; j < nodes.length; j++) {
            var dx = nodes[i].x - nodes[j].x;
            var dy = nodes[i].y - nodes[j].y;
            var dist = Math.sqrt(dx * dx + dy * dy) || 1;
            var force = simParams.attraction / (dist * dist);
            var fx = (dx / dist) * force;
            var fy = (dy / dist) * force;
            nodes[i].vx += fx;
            nodes[i].vy += fy;
            nodes[j].vx -= fx;
            nodes[j].vy -= fy;
        }
    }

    // Hooke's law spring forces along edges
    for (var s = 0; s < springs.length; s++) {
        var nodeA = findNodeById(springs[s].a);
        var nodeB = findNodeById(springs[s].b);
        if (!nodeA || !nodeB) continue;
        var dx = nodeB.x - nodeA.x;
        var dy = nodeB.y - nodeA.y;
        var dist = Math.sqrt(dx * dx + dy * dy) || 1;
        var displacement = dist - springs[s].rest;
        var force = (springs[s].k || simParams.springCoeff) * displacement;
        nodeA.vx += (dx / dist) * force;
        nodeA.vy += (dy / dist) * force;
        nodeB.vx -= (dx / dist) * force;
        nodeB.vy -= (dy / dist) * force;
    }

    // Centering gravity, velocity damping, and position integration
    // Control flow was: "4|0|2|3|5|1"
    for (var n = 0; n < nodes.length; n++) {
        // case 4: centering gravity X
        nodes[n].vx += (400 - nodes[n].x) * simParams.gravityStrength;
        // case 0: centering gravity Y
        nodes[n].vy += (300 - nodes[n].y) * simParams.gravityStrength;
        // case 2: dampen vx
        nodes[n].vx *= simParams.amplification;
        // case 3: dampen vy
        nodes[n].vy *= simParams.amplification;
        // case 5: integrate position X
        nodes[n].x += nodes[n].vx;
        // case 1: integrate position Y
        nodes[n].y += nodes[n].vy;
    }
}

// Spawn a new particle from a random node
function spawnParticle() {     // a0_0x152f59
    if (particles.length >= simParams.streamLimit) return;
    var sourceNode = nodes[Math.floor(Math.random() * nodes.length)];
    var angle = Math.random() * TAU;
    var speed = 0.3 + Math.random() * SQRT_HALF;
    particles.push({
        x: sourceNode.x,
        y: sourceNode.y,
        vx: Math.cos(angle) * speed,
        vy: Math.sin(angle) * speed,
        age: 0,
        maxAge: 800 + Math.random() * 1200,
        size: 0.8 + (Math.random() * GOLDEN_RATIO) * SQRT_HALF
    });
}

// Update particles: move, apply drag, remove expired
function updateParticles() {   // a0_0xe5bcd5
    // Control flow was: "1|0|3|4|2|6|5"
    for (var i = particles.length - 1; i >= 0; i--) {
        var p = particles[i];      // case 1
        p.age++;                    // case 0
        // case 3: drag on vx
        p.vx *= (1 - simParams.streamDecay * 0.125);
        // case 4: drag on vy
        p.vy *= (1 - simParams.streamDecay * 0.125);
        // case 2: remove if expired
        if (p.age > p.maxAge) particles.splice(i, 1);
        // case 6: integrate X
        p.x += p.vx;
        // case 5: integrate Y
        p.y += p.vy;
    }
}

// Smoothly interpolate camera toward target
function updateCamera() {      // a0_0x192e84
    camera.x += (cameraTarget.x - camera.x) * simParams.theta;
    camera.y += (cameraTarget.y - camera.y) * simParams.theta;
    camera.zoom += (cameraTarget.zoom - camera.zoom) * simParams.theta;
}

// Main tick function
function tick() {              // a0_0x39886d
    applyPhysics();
    updateParticles();
    updateCamera();
    if (frameCount % 3 === 0) spawnParticle();
    frameCount++;
}

setInterval(tick, 16);  // ~60 FPS
```

